/*
 * aligner.c — single-file build of the aligner, generated by
 * tools/build_single.sh.
 *
 * Compile and link with libc only:
 *     cc -std=c99 -O2 -o aligner aligner.c
 *
 * The full project source tree (lexer + parser + AST + passes + emit +
 * align, plus the data-structures library it depends on) lives separately
 * and is what's actually tested. This file is its concatenation, with the
 * project's own headers inlined and the ds library replaced by a minimal
 * shim covering exactly the 27 symbols the aligner uses.
 *
 * Last regenerated: 2026-05-30T09:49:05Z
 */

#include <stdarg.h>
#include <stddef.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* --- ds shim: minimal stand-ins for the symbols the aligner uses ---------
 * Used only in the single-file amalgam build. The full project uses the
 * real ds library; this shim provides bug-for-bug-compatible drop-ins for
 * the 27 symbols we touch, so the amalgam compiles with libc only.
 */

typedef enum {
    DS_OK            =  0,
    DS_NOT_FOUND     =  1,
    DS_ERR_ALLOC     = -1,
    DS_ERR_INVALID   = -2,
    DS_ERR_NULL      = -3,
    DS_ERR_INTERNAL  = -10
} ds_status_t;

static const char *ds_status_name(ds_status_t s) {
    switch (s) {
        case DS_OK:            return "DS_OK";
        case DS_NOT_FOUND:     return "DS_NOT_FOUND";
        case DS_ERR_ALLOC:     return "DS_ERR_ALLOC";
        case DS_ERR_INVALID:   return "DS_ERR_INVALID";
        case DS_ERR_NULL:      return "DS_ERR_NULL";
        case DS_ERR_INTERNAL:  return "DS_ERR_INTERNAL";
    }
    return "?";
}

/* Arena: singly linked list of (block-header + payload). Allocator returns
   payload pointer; arena_destroy frees every block. */
struct ds__arena_block { struct ds__arena_block *next; };

typedef struct {
    struct ds__arena_block *head;
} ds_arena_t;

typedef struct {
    ds_arena_t *arena;
} ds_context_t;

static void ds_context_init(ds_context_t *c) { c->arena = NULL; }

static ds_status_t ds_arena_create(ds_arena_t *a, size_t cap_hint, ds_context_t *c) {
    (void)cap_hint; (void)c;
    a->head = NULL;
    return DS_OK;
}

static void ds_context_use_arena(ds_context_t *c, ds_arena_t *a) { c->arena = a; }

static void *ds_context_alloc(ds_context_t *c, size_t n) {
    struct ds__arena_block *b;
    if (!c || !c->arena) return malloc(n);
    b = (struct ds__arena_block *)malloc(sizeof(*b) + n);
    if (!b) return NULL;
    b->next = c->arena->head;
    c->arena->head = b;
    return (void *)(b + 1);
}

static void ds_arena_destroy(ds_arena_t *a, ds_context_t *c) {
    struct ds__arena_block *b = a->head, *nx;
    (void)c;
    while (b) { nx = b->next; free(b); b = nx; }
    a->head = NULL;
}

/* Dynamic string buffer. */
typedef struct ds_str {
    char  *buf;
    size_t len;
    size_t cap;
} ds_str_t;

static ds_str_t *str_create(void) {
    ds_str_t *s = (ds_str_t *)malloc(sizeof(*s));
    if (!s) return NULL;
    s->buf = NULL; s->len = 0; s->cap = 0;
    return s;
}
static void str_destroy(ds_str_t *s) {
    if (!s) return;
    free(s->buf);
    free(s);
}
static int str__reserve(ds_str_t *s, size_t need) {
    char *nb;
    size_t newcap;
    if (s->cap >= need) return 0;
    newcap = s->cap ? s->cap : 64;
    while (newcap < need) newcap *= 2;
    nb = (char *)realloc(s->buf, newcap);
    if (!nb) return -1;
    s->buf = nb; s->cap = newcap;
    return 0;
}
static int str_append(ds_str_t *s, const void *data, size_t n) {
    if (str__reserve(s, s->len + n + 1) != 0) return -1;
    memcpy(s->buf + s->len, data, n);
    s->len += n;
    s->buf[s->len] = '\0';
    return 0;
}
static int str_append_cstr(ds_str_t *s, const char *c) {
    return str_append(s, c, strlen(c));
}
static int str_pushc(ds_str_t *s, int c) {
    char b = (char)c;
    return str_append(s, &b, 1);
}
static int str_append_vfmt(ds_str_t *s, const char *fmt, va_list ap) {
    va_list ap2;
    int n;
    va_copy(ap2, ap);
    n = vsnprintf(NULL, 0, fmt, ap2);
    va_end(ap2);
    if (n < 0) return -1;
    if (str__reserve(s, s->len + (size_t)n + 1) != 0) return -1;
    vsnprintf(s->buf + s->len, s->cap - s->len, fmt, ap);
    s->len += (size_t)n;
    return 0;
}
#define FUNC_str_len(s)  ((s) ? (s)->len : (size_t)0)
#define FUNC_str_data(s) ((s) ? (s)->buf : (char *)"")

/* String-keyed map. Linear chain — N is small in our usage. */
struct ds__sm_node {
    char *key;
    void *value;
    struct ds__sm_node *next;
};
typedef struct ds_string_map {
    struct ds__sm_node *head;
    ds_context_t       *ctx;
} ds_string_map_t;

static ds_string_map_t *ds_string_map_create_ctx(ds_context_t *c) {
    ds_string_map_t *m = (ds_string_map_t *)ds_context_alloc(c, sizeof(*m));
    if (!m) return NULL;
    m->head = NULL;
    m->ctx  = c;
    return m;
}
static ds_status_t ds_string_map_put(ds_string_map_t *m, const char *key, void *value) {
    struct ds__sm_node *n;
    size_t klen;
    if (!m || !key) return DS_ERR_NULL;
    for (n = m->head; n; n = n->next) {
        if (strcmp(n->key, key) == 0) { n->value = value; return DS_OK; }
    }
    n = (struct ds__sm_node *)ds_context_alloc(m->ctx, sizeof(*n));
    if (!n) return DS_ERR_ALLOC;
    klen = strlen(key);
    n->key = (char *)ds_context_alloc(m->ctx, klen + 1);
    if (!n->key) return DS_ERR_ALLOC;
    memcpy(n->key, key, klen + 1);
    n->value = value;
    n->next  = m->head;
    m->head  = n;
    return DS_OK;
}
static ds_status_t ds_string_map_get(ds_string_map_t *m, const char *key, void **out) {
    struct ds__sm_node *n;
    if (out) *out = NULL;
    if (!m || !key) return DS_ERR_NULL;
    for (n = m->head; n; n = n->next) {
        if (strcmp(n->key, key) == 0) {
            if (out) *out = n->value;
            return DS_OK;
        }
    }
    return DS_NOT_FOUND;
}


/* ============================================================
 * lexer.h
 * ============================================================
 */
/*
 * lexer.h — tokenize C source.
 *
 * The lexer is lossless: every byte of input is accounted for by exactly one
 * token, including whitespace, newlines, and comments. This lets the emitter
 * reproduce the source bytewise when no transformations apply.
 *
 * Preprocessor directives are a single token (TOK_PP_DIRECTIVE) covering the
 * entire logical line, including any `\<newline>` continuations. The parser
 * does not look inside them; passes that need to (e.g., to recognise
 * #include) examine the lexeme.
 *
 * Adjacent string literals are NOT merged here — each "..." segment is its
 * own TOK_STRING_LIT. The parser/emit phase decides what to do with runs of
 * adjacent string tokens.
 */
#ifndef CFMT_LEXER_H
#define CFMT_LEXER_H



typedef enum {
    TOK_EOF = 0,
    TOK_IDENT,          /* foo, _bar, sizeof, if, while — keywords undistinguished */
    TOK_INT_LIT,        /* 123, 0x1A, 0777, 0b1010, suffix included */
    TOK_FLOAT_LIT,      /* 1.0, 1e10, .5f, 0x1.8p+1 */
    TOK_CHAR_LIT,       /* 'X', '\n', L'A', u'A', U'A' */
    TOK_STRING_LIT,     /* "...", L"...", u"...", U"...", u8"..." */
    TOK_PUNCT,          /* operators and punctuators: ;, (, ), {, }, +, ==, ->, ... */
    TOK_PP_DIRECTIVE,   /* one full logical # line incl. continuations */
    TOK_COMMENT_LINE,   /* //... up to but not including the newline */
    TOK_COMMENT_BLOCK,  /* slash-star ... star-slash, may span lines */
    TOK_WHITESPACE,     /* runs of spaces/tabs/etc., NOT newlines */
    TOK_NEWLINE         /* a single \n */
} cfmt_tok_kind_t;

/* String- and char-literal "encoding prefix". */
typedef enum {
    CFMT_ENC_NONE = 0,  /* plain "..." */
    CFMT_ENC_L,         /* L"..." */
    CFMT_ENC_u,         /* u"..." */
    CFMT_ENC_U,         /* U"..." */
    CFMT_ENC_u8         /* u8"..." */
} cfmt_enc_t;

typedef struct cfmt_tok {
    cfmt_tok_kind_t kind;

    /* Verbatim source slice for this token. Points into the source buffer
       given to cfmt_lex(); do not free. */
    const char *lexeme;
    size_t      lexeme_len;

    /* 1-based, for diagnostics. */
    unsigned line;
    unsigned col;

    /* Decoded form for literals. Arena-allocated. */
    union {
        struct {
            unsigned char *bytes;
            size_t         byte_count;
            cfmt_enc_t     enc;
        } str;
        struct {
            unsigned long value;  /* enough for hex/octal large values */
            cfmt_enc_t     enc;
        } chr;
    } u;
} cfmt_tok_t;

/* Token stream — owned by the arena and the caller. */
typedef struct cfmt_tok_stream {
    cfmt_tok_t *tokens;
    size_t      count;
    size_t      cap;

    /* Owned by caller; allocations charged here. */
    ds_arena_t   *arena;
    ds_context_t *ctx;

    /* For pointer arithmetic in lexeme spans. */
    const char *source;
    size_t      source_len;
} cfmt_tok_stream_t;

/*
 * Tokenize `source` into `out`.
 * `out` should be zero-initialized; arena and ctx must be set.
 * Returns DS_OK on success, DS_ERR_* on allocation/IO failure.
 */
ds_status_t cfmt_lex(const char       *source,
                     size_t            source_len,
                     ds_context_t     *ctx,
                     ds_arena_t       *arena,
                     cfmt_tok_stream_t *out);

/* Human-readable name for a token kind. Useful in tests and diagnostics. */
const char *cfmt_tok_kind_name(cfmt_tok_kind_t k);

/* True if `t` is a punctuator with lexeme equal to the given C string. */
int cfmt_tok_is_punct(const cfmt_tok_t *t, const char *punct);

/* True if `t` is an identifier with lexeme equal to the given C string. */
int cfmt_tok_is_ident(const cfmt_tok_t *t, const char *ident);

#endif /* CFMT_LEXER_H */

/* ============================================================
 * ast.h
 * ============================================================
 */
/*
 * ast.h — coarse AST for cfmt.
 *
 * Design philosophy: a structural skeleton, not a full C parse tree. We track
 * what kind of region each token range belongs to (top-level entity, function
 * body, nested block) so that passes can answer "what scope owns this string
 * literal?" without doing semantic analysis.
 *
 * Nodes form a tree with explicit parent / first_child / next_sibling links.
 * Each node owns a half-open token range [first_tok, last_tok) into the token
 * stream the parser was given.
 *
 * All nodes are arena-allocated. There is no destroy step; the arena is
 * dropped when parsing is finished with.
 */
#ifndef CFMT_AST_H
#define CFMT_AST_H



typedef enum {
    AST_TRANSLATION_UNIT = 0,
    AST_PP_DIRECTIVE,      /* a single PP line */
    AST_DECL,              /* file-scope declaration ending in ; */
    AST_FUNC_DEF,          /* function definition */
    AST_BLOCK,             /* { ... } compound region inside a function */
    AST_UNKNOWN            /* couldn't classify — passes pass it through raw */
} cfmt_ast_kind_t;

typedef struct cfmt_ast {
    cfmt_ast_kind_t kind;

    /* Half-open token range [first_tok_idx, last_tok_idx) into the stream
       given to cfmt_parse(). last_tok_idx is one past the last covered
       token, so first_tok_idx == last_tok_idx implies an empty range. */
    size_t first_tok_idx;
    size_t last_tok_idx;

    /* Tree links. */
    struct cfmt_ast *parent;
    struct cfmt_ast *first_child;
    struct cfmt_ast *last_child;
    struct cfmt_ast *next_sibling;

    /* For AST_FUNC_DEF: where the body's `{` is (token index). For AST_BLOCK
       and AST_FUNC_DEF, also where the matching `}` is. */
    size_t open_brace_idx;   /* index of { token; SIZE_MAX if N/A */
    size_t close_brace_idx;  /* index of } token; SIZE_MAX if N/A */
} cfmt_ast_t;

/* Parse `stream` into an AST. Returns the root (AST_TRANSLATION_UNIT) or NULL
   on allocation failure. All nodes allocated via the context. */
cfmt_ast_t *cfmt_parse(cfmt_tok_stream_t *stream, ds_context_t *ctx);

/* Walk the AST in pre-order, invoking `visit` for each node. The visitor may
   read the node but must not mutate the tree. If `visit` returns non-zero,
   the walk stops and the value is returned. */
int cfmt_ast_walk(cfmt_ast_t *root,
                  int (*visit)(cfmt_ast_t *node, void *user),
                  void *user);

/* Find the deepest AST_FUNC_DEF ancestor of `node`, or NULL if at file scope. */
cfmt_ast_t *cfmt_ast_enclosing_func(cfmt_ast_t *node);

/* Human-readable kind name (for debugging). */
const char *cfmt_ast_kind_name(cfmt_ast_kind_t k);

/* Dump the tree to `out` as nested s-expressions for debugging. */
void cfmt_ast_dump(cfmt_ast_t *root, const cfmt_tok_stream_t *stream, FILE *out);

#endif /* CFMT_AST_H */

/* ============================================================
 * parser.h
 * ============================================================
 */
/*
 * parser.h — token stream → AST.
 *
 * The parser is structural: it identifies top-level entities (preprocessor
 * directives, declarations, function definitions) and recursively models
 * brace-nested blocks inside function bodies. It does not attempt to parse
 * expression structure, types, or anything that would require name
 * resolution.
 */
#ifndef CFMT_PARSER_H
#define CFMT_PARSER_H


cfmt_ast_t *cfmt_parse(cfmt_tok_stream_t *stream, ds_context_t *ctx);

#endif /* CFMT_PARSER_H */

/* ============================================================
 * pass.h
 * ============================================================
 */
/*
 * pass.h — analysis passes over the AST.
 *
 * Passes do not mutate the AST. They produce side data that the emitter
 * consumes. Right now we have one pass — destring — but the result struct
 * is designed so we can add more.
 */
#ifndef CFMT_PASS_H
#define CFMT_PASS_H



/* One unique string literal, deduplicated by hash within its scope. */
typedef struct cfmt_lit_entry {
    unsigned int hash;
    unsigned char *bytes;     /* arena-owned copy of decoded content */
    size_t         byte_count;
} cfmt_lit_entry_t;

/* Ordered set of literal entries — deduplicated and stably ordered (by
 * first-seen order, so emit is deterministic). */
typedef struct cfmt_lit_table {
    cfmt_lit_entry_t **entries;   /* dynamic array */
    size_t count;
    size_t cap;
    ds_string_map_t *by_hash;     /* hex hash → entry ptr (dedup) */
    ds_context_t   *ctx;
} cfmt_lit_table_t;

/* What to do with a particular token at emit time. */
typedef enum {
    CFMT_ACT_NONE = 0,         /* keep as-is */
    CFMT_ACT_VAR_REF,          /* STRING_LIT → reference to sXXX variable */
    CFMT_ACT_BRACE_INIT,       /* STRING_LIT → {b, b, ..., 0} for char[] init */
    CFMT_ACT_CHAR_NUM,         /* CHAR_LIT → decimal integer value */
    CFMT_ACT_OMIT              /* trailing token in adjacent-string run */
} cfmt_action_kind_t;

typedef struct cfmt_action {
    cfmt_action_kind_t kind;
    cfmt_lit_entry_t  *entry;  /* for VAR_REF / BRACE_INIT */
} cfmt_action_t;

/* Per-AST-node side data for emit. We use a simple resizable array indexed
 * by sequential function index (0, 1, 2, ...) — the emitter walks FUNC_DEFs
 * in source order and reads func_lits[seen_so_far]. */
typedef struct cfmt_pass_result {
    cfmt_lit_table_t  file_lits;       /* file-scope literals */
    cfmt_lit_table_t *func_lits;       /* one per FUNC_DEF in source order */
    size_t            func_lits_count;
    size_t            func_lits_cap;

    cfmt_action_t    *actions;         /* size == stream->count */
    size_t            actions_count;

    ds_context_t     *ctx;
} cfmt_pass_result_t;

/* Initialize a fresh pass result. The caller-supplied context drives all
   allocations. */
ds_status_t cfmt_pass_result_init(cfmt_pass_result_t *r,
                                  cfmt_tok_stream_t *stream,
                                  ds_context_t      *ctx);

/* Run the destringer pass.
 * For every STRING_LIT token, register it in the appropriate literal table
 * (file scope or its enclosing function scope) and record an emit action.
 * For every CHAR_LIT token whose use-context is not the lexeme inside a
 * preprocessor directive (those are inside PP tokens already), record a
 * CHAR_NUM action. */
ds_status_t cfmt_pass_destring(cfmt_ast_t        *root,
                               cfmt_tok_stream_t *stream,
                               cfmt_pass_result_t *result);

/* FNV-1a 32-bit (exposed for tests). */
unsigned int cfmt_fnv1a(const unsigned char *data, size_t n);

#endif /* CFMT_PASS_H */

/* ============================================================
 * emit.h
 * ============================================================
 */
/*
 * emit.h — AST + actions → unaligned text.
 *
 * The emitter walks the AST in pre-order. It outputs:
 *   1. A preamble of file-scope literal declarations.
 *   2. For each token, either its lexeme verbatim or its planned action's
 *      replacement (var-ref, brace-init, char-num, or omit).
 *   3. At each function-body open `{`, the function's local literal
 *      declarations (followed by per-byte assignments) before the rest of
 *      the body's tokens.
 *
 * The output format is line-oriented and intentionally produces many short
 * lines (one byte per line within brace inits and assignments). The aligner
 * then reflows each line to exactly 80 columns.
 */
#ifndef CFMT_EMIT_H
#define CFMT_EMIT_H


/* Emit unaligned text into `out` (an already-created ds_str_t). */
ds_status_t cfmt_emit(cfmt_ast_t        *root,
                      cfmt_tok_stream_t *stream,
                      cfmt_pass_result_t *result,
                      ds_str_t          *out);

#endif /* CFMT_EMIT_H */

/* ============================================================
 * align.h
 * ============================================================
 */
/*
 * align.h — line-oriented right-justifier.
 *
 * For each input line, split into:
 *   - word prefix:  leading-whitespace-stripped run of `word | space` chars,
 *                   where `word` = letter | digit | underscore. Trailing
 *                   spaces are stripped.
 *   - symbol tail:  everything from the first "symbol" character onward.
 *
 * Output: word prefix, then spaces, then symbol tail; total width 80.
 * If the natural length already exceeds 80, no padding is inserted (the line
 * is emitted as-is).
 *
 * Blank lines (or lines containing only whitespace) are emitted as a single
 * newline.
 */
#ifndef CFMT_ALIGN_H
#define CFMT_ALIGN_H


ds_status_t cfmt_align(const char *in, size_t in_len, ds_str_t *out);

#endif /* CFMT_ALIGN_H */

/* ============================================================
 * lexer.c
 * ============================================================
 */
/*
 * lexer.c — tokenizer for the aligner parser.
 *
 * Lossless: every input byte ends up inside exactly one token. The emitter can
 * reproduce the source bytewise by walking tokens and printing their lexemes.
 *
 * Not handled (and we don't pretend otherwise):
 *  - Trigraphs (??=, ??-, etc.). Nearly extinct; bypass via cpp.
 *  - Digraphs (<:, :>, <%, %>, %:). Recognised as their constituent
 *    punctuators rather than as a single token. Fine for our purposes.
 *  - `\<newline>` line splicing outside string/PP-directive context. Rare.
 *
 * Where the spec is ambiguous about how to split tokens (e.g. maximal munch
 * on punctuators), we follow the C standard.
 */



/* --- Token kind name lookup ------------------------------------------------ */

const char *cfmt_tok_kind_name(cfmt_tok_kind_t k) {
    switch (k) {
        case TOK_EOF:           return "EOF";
        case TOK_IDENT:         return "IDENT";
        case TOK_INT_LIT:       return "INT_LIT";
        case TOK_FLOAT_LIT:     return "FLOAT_LIT";
        case TOK_CHAR_LIT:      return "CHAR_LIT";
        case TOK_STRING_LIT:    return "STRING_LIT";
        case TOK_PUNCT:         return "PUNCT";
        case TOK_PP_DIRECTIVE:  return "PP_DIRECTIVE";
        case TOK_COMMENT_LINE:  return "COMMENT_LINE";
        case TOK_COMMENT_BLOCK: return "COMMENT_BLOCK";
        case TOK_WHITESPACE:    return "WHITESPACE";
        case TOK_NEWLINE:       return "NEWLINE";
    }
    return "?";
}

/* --- Predicate helpers ---------------------------------------------------- */

static int is_id_start(int c) {
    return c == '_' || (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z');
}
static int is_id_cont(int c) {
    return is_id_start(c) || (c >= '0' && c <= '9');
}
static int is_digit(int c)     { return c >= '0' && c <= '9'; }
static int is_octal(int c)     { return c >= '0' && c <= '7'; }
static int is_hex(int c)       {
    return is_digit(c) || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F');
}
static int hex_val(int c) {
    if (c >= '0' && c <= '9') return c - '0';
    if (c >= 'a' && c <= 'f') return c - 'a' + 10;
    return c - 'A' + 10;
}
static int is_hspace(int c) {
    /* horizontal whitespace, NOT newline */
    return c == ' ' || c == '\t' || c == '\v' || c == '\f' || c == '\r';
}

/* --- Lexer state ---------------------------------------------------------- */

typedef struct {
    const char *p;       /* current cursor */
    const char *end;     /* one past last byte */
    unsigned    line;
    unsigned    col;
    int         line_start; /* 1 if only whitespace has been seen since last \n */
    cfmt_tok_stream_t *out;
} lexer_t;

static int lex_peek(const lexer_t *L, size_t off) {
    if (L->p + off >= L->end) return 0;
    return (unsigned char)L->p[off];
}

static void advance(lexer_t *L, size_t n) {
    for (size_t i = 0; i < n && L->p < L->end; i++) {
        if (*L->p == '\n') { L->line++; L->col = 1; }
        else                { L->col++; }
        L->p++;
    }
}

typedef struct { const char *start; unsigned line; unsigned col; } mark_t;
static mark_t take_mark(const lexer_t *L) {
    mark_t m; m.start = L->p; m.line = L->line; m.col = L->col;
    return m;
}

/* Token stream grow / emit. */
static ds_status_t push_tok(lexer_t *L, const cfmt_tok_t *tok) {
    cfmt_tok_stream_t *s = L->out;
    if (s->count >= s->cap) {
        size_t newcap = s->cap ? s->cap * 2 : 256;
        size_t bytes  = newcap * sizeof(cfmt_tok_t);
        cfmt_tok_t *nb = (cfmt_tok_t *)realloc(s->tokens, bytes);
        if (!nb) return DS_ERR_ALLOC;
        s->tokens = nb;
        s->cap    = newcap;
    }
    s->tokens[s->count++] = *tok;
    return DS_OK;
}

static void fill_span(cfmt_tok_t *t, cfmt_tok_kind_t k, const lexer_t *L, mark_t m) {
    t->kind        = k;
    t->lexeme      = m.start;
    t->lexeme_len  = (size_t)(L->p - m.start);
    t->line        = m.line;
    t->col         = m.col;
    memset(&t->u, 0, sizeof(t->u));
}

/* --- Whitespace and newlines --------------------------------------------- */

static ds_status_t lex_whitespace(lexer_t *L) {
    mark_t m = take_mark(L);
    while (L->p < L->end && is_hspace(*L->p)) advance(L, 1);
    cfmt_tok_t t;
    fill_span(&t, TOK_WHITESPACE, L, m);
    return push_tok(L, &t);
}

static ds_status_t lex_newline(lexer_t *L) {
    mark_t m = take_mark(L);
    advance(L, 1);
    cfmt_tok_t t;
    fill_span(&t, TOK_NEWLINE, L, m);
    L->line_start = 1;
    return push_tok(L, &t);
}

/* --- Comments ------------------------------------------------------------- */

static ds_status_t lex_line_comment(lexer_t *L) {
    mark_t m = take_mark(L);
    advance(L, 2);  /* eat // */
    while (L->p < L->end && *L->p != '\n') advance(L, 1);
    cfmt_tok_t t;
    fill_span(&t, TOK_COMMENT_LINE, L, m);
    return push_tok(L, &t);
}

static ds_status_t lex_block_comment(lexer_t *L) {
    mark_t m = take_mark(L);
    advance(L, 2);  /* eat the opening slash-star */
    while (L->p + 1 < L->end && !(L->p[0] == '*' && L->p[1] == '/')) advance(L, 1);
    if (L->p + 1 < L->end) advance(L, 2);  /* eat the closing */
    cfmt_tok_t t;
    fill_span(&t, TOK_COMMENT_BLOCK, L, m);
    return push_tok(L, &t);
}

/* --- Preprocessor directive (entire logical line) ------------------------ */

static ds_status_t lex_pp_directive(lexer_t *L) {
    mark_t m = take_mark(L);
    while (L->p < L->end) {
        char c = *L->p;
        if (c == '\\' && L->p + 1 < L->end && L->p[1] == '\n') {
            advance(L, 2);  /* line continuation: keep going */
            continue;
        }
        if (c == '\n') break;
        advance(L, 1);
    }
    cfmt_tok_t t;
    fill_span(&t, TOK_PP_DIRECTIVE, L, m);
    return push_tok(L, &t);
}

/* --- Identifiers and keywords -------------------------------------------- */

/* Caller has confirmed L->p[0] is id-start, OR is one of L/u/U preceding "/'. */
static ds_status_t lex_ident(lexer_t *L) {
    mark_t m = take_mark(L);
    while (L->p < L->end && is_id_cont(*L->p)) advance(L, 1);
    cfmt_tok_t t;
    fill_span(&t, TOK_IDENT, L, m);
    return push_tok(L, &t);
}

/* --- Numeric literals ---------------------------------------------------- */

/*
 * We don't fully decode the numeric value — the parser doesn't need it. We
 * only need to find the end of the lexeme correctly. We distinguish int vs
 * float by the presence of '.', 'e', 'E', 'p', 'P' (hex float exponent).
 */
static ds_status_t lex_number(lexer_t *L) {
    mark_t m   = take_mark(L);
    int is_float = 0;
    int is_hex_num = 0;

    /* Optional prefix: 0x / 0b / 0o (C2x) / leading 0 (octal). */
    if (L->p[0] == '0' && L->p + 1 < L->end &&
        (L->p[1] == 'x' || L->p[1] == 'X')) {
        is_hex_num = 1;
        advance(L, 2);
    } else if (L->p[0] == '0' && L->p + 1 < L->end &&
               (L->p[1] == 'b' || L->p[1] == 'B')) {
        advance(L, 2);
    }

    /* Body: digits / a-fA-F / ' (digit separator in C23) / single . */
    int seen_dot = 0;
    while (L->p < L->end) {
        char c = *L->p;
        if (c == '\'') { /* C23 digit separator */ advance(L, 1); continue; }
        if (c == '.') {
            if (seen_dot) break;
            seen_dot = 1; is_float = 1; advance(L, 1); continue;
        }
        if (is_hex_num) {
            if (is_hex((unsigned char)c)) { advance(L, 1); continue; }
        } else {
            if (is_digit((unsigned char)c)) { advance(L, 1); continue; }
        }
        break;
    }

    /* Exponent: e/E for decimal, p/P for hex floats. */
    if (L->p < L->end) {
        char c = *L->p;
        int has_exp =
            (!is_hex_num && (c == 'e' || c == 'E')) ||
            ( is_hex_num && (c == 'p' || c == 'P'));
        if (has_exp) {
            is_float = 1;
            advance(L, 1);
            if (L->p < L->end && (*L->p == '+' || *L->p == '-')) advance(L, 1);
            while (L->p < L->end && is_digit((unsigned char)*L->p)) advance(L, 1);
        }
    }

    /* Suffix: u, U, l, L, ll, LL, lu, llu, f, F, etc. — accept up to 4 chars. */
    for (int i = 0; i < 4; i++) {
        if (L->p >= L->end) break;
        char c = *L->p;
        if (c == 'u' || c == 'U' || c == 'l' || c == 'L' ||
            c == 'f' || c == 'F' || c == 'i' || c == 'I' ||
            c == 'j' || c == 'J') {
            advance(L, 1);
        } else break;
    }

    cfmt_tok_t t;
    fill_span(&t, is_float ? TOK_FLOAT_LIT : TOK_INT_LIT, L, m);
    return push_tok(L, &t);
}

/* --- Escape sequence decoding -------------------------------------------- */

/* Decode escape starting at L->p (which points to the char AFTER the backslash).
 * Returns the byte value and advances L->p past the escape. */
static int parse_escape(lexer_t *L) {
    if (L->p >= L->end) return 0;
    int c = (unsigned char)*L->p;

    /* Hex: \xHH... — any number of hex digits per the standard */
    if (c == 'x' || c == 'X') {
        advance(L, 1);
        int val = 0;
        while (L->p < L->end && is_hex((unsigned char)*L->p)) {
            val = (val << 4) | hex_val((unsigned char)*L->p);
            advance(L, 1);
        }
        return val & 0xFF;
    }
    /* Octal: \NNN — up to 3 octal digits */
    if (is_octal(c)) {
        int val = 0;
        for (int i = 0; i < 3 && L->p < L->end && is_octal((unsigned char)*L->p); i++) {
            val = (val * 8) + (*L->p - '0');
            advance(L, 1);
        }
        return val & 0xFF;
    }
    /* Universal char names: \uHHHH or \UHHHHHHHH — return low byte if <256 */
    if (c == 'u' || c == 'U') {
        int width = (c == 'u') ? 4 : 8;
        advance(L, 1);
        int val = 0;
        for (int i = 0; i < width && L->p < L->end && is_hex((unsigned char)*L->p); i++) {
            val = (val << 4) | hex_val((unsigned char)*L->p);
            advance(L, 1);
        }
        return val & 0xFF;
    }

    advance(L, 1);
    switch (c) {
        case 'n':  return 10;
        case 't':  return 9;
        case 'r':  return 13;
        case '0':  return 0;
        case '\\': return 92;
        case '"':  return 34;
        case '\'': return 39;
        case 'a':  return 7;
        case 'b':  return 8;
        case 'f':  return 12;
        case 'v':  return 11;
        case '?':  return 63;
        case 'e':  return 27;   /* GCC extension */
        default:   return c;    /* unknown escape — pass through */
    }
}

/* --- Character literals --------------------------------------------------- */

/* Caller has positioned L->p at the opening quote. `enc` is the prefix (or NONE). */
static ds_status_t lex_char_lit(lexer_t *L, cfmt_enc_t enc, mark_t m) {
    advance(L, 1);  /* eat opening ' */

    unsigned long value = 0;

    /* Multi-character literals like 'AB' are implementation-defined but legal.
       We accumulate bytes into `value` shift-left-and-or, lo-byte-last. */
    while (L->p < L->end && *L->p != '\'') {
        int b;
        if (*L->p == '\\' && L->p + 1 < L->end) {
            advance(L, 1);
            b = parse_escape(L);
        } else {
            b = (unsigned char)*L->p;
            advance(L, 1);
        }
        value = (value << 8) | (unsigned long)(b & 0xFF);
    }
    if (L->p < L->end) advance(L, 1);  /* closing ' */

    cfmt_tok_t t;
    fill_span(&t, TOK_CHAR_LIT, L, m);
    t.u.chr.value = value;
    t.u.chr.enc   = enc;
    return push_tok(L, &t);
}

/* --- String literals ------------------------------------------------------ */

/* Decode a string literal's bytes into an arena-allocated buffer.
 * Caller has positioned L->p at the opening ". `enc` is the prefix. */
static ds_status_t lex_string_lit(lexer_t *L, cfmt_enc_t enc, mark_t m) {
    advance(L, 1);  /* eat opening " */

    /* Two-pass approach would be cleaner, but a single growing buffer in the
       arena works because we know the upper bound is lexeme_len. We'll
       allocate optimistically and trim by tracking actual length. */
    /* Upper bound: distance from current point to first matching " — at most
       the remaining input size. Cheap to over-allocate. */
    size_t cap = 16;
    unsigned char *buf = (unsigned char *)ds_context_alloc(L->out->ctx, cap);
    if (!buf) return DS_ERR_ALLOC;
    size_t len = 0;

    while (L->p < L->end && *L->p != '"') {
        int b;
        if (*L->p == '\\' && L->p + 1 < L->end) {
            if (L->p[1] == '\n') {
                /* Line continuation inside string literal. */
                advance(L, 2);
                continue;
            }
            advance(L, 1);
            b = parse_escape(L);
        } else {
            b = (unsigned char)*L->p;
            advance(L, 1);
        }
        if (len >= cap) {
            size_t newcap = cap * 2;
            unsigned char *nb = (unsigned char *)ds_context_alloc(L->out->ctx, newcap);
            if (!nb) return DS_ERR_ALLOC;
            memcpy(nb, buf, len);
            buf = nb;
            cap = newcap;
            /* Old buf leaks in the arena, which is fine. */
        }
        buf[len++] = (unsigned char)(b & 0xFF);
    }
    if (L->p < L->end) advance(L, 1);  /* closing " */

    cfmt_tok_t t;
    fill_span(&t, TOK_STRING_LIT, L, m);
    t.u.str.bytes      = buf;
    t.u.str.byte_count = len;
    t.u.str.enc        = enc;
    return push_tok(L, &t);
}

/* --- Punctuators ---------------------------------------------------------- */

/*
 * Maximal munch over the C punctuator set. We try 4-char, then 3-char, then
 * 2-char, then 1-char.
 */
static const char *const PUNCT_4[] = { "%:%:", NULL };
static const char *const PUNCT_3[] = {
    "<<=", ">>=", "...", "->*", "::*", NULL
};
static const char *const PUNCT_2[] = {
    "<<", ">>", "<=", ">=", "==", "!=", "&&", "||", "++", "--",
    "+=", "-=", "*=", "/=", "%=", "&=", "|=", "^=", "->", "::",
    "##", NULL
};

static int try_match(const char *p, const char *end, const char *needle, size_t n) {
    if ((size_t)(end - p) < n) return 0;
    return memcmp(p, needle, n) == 0;
}

static ds_status_t lex_punct(lexer_t *L) {
    mark_t m = take_mark(L);
    size_t avail = (size_t)(L->end - L->p);
    size_t take  = 0;
    if (avail >= 4) {
        for (int i = 0; PUNCT_4[i]; i++) {
            if (memcmp(L->p, PUNCT_4[i], 4) == 0) { take = 4; break; }
        }
    }
    if (!take && avail >= 3) {
        for (int i = 0; PUNCT_3[i]; i++) {
            if (memcmp(L->p, PUNCT_3[i], 3) == 0) { take = 3; break; }
        }
    }
    if (!take && avail >= 2) {
        for (int i = 0; PUNCT_2[i]; i++) {
            if (memcmp(L->p, PUNCT_2[i], 2) == 0) { take = 2; break; }
        }
    }
    if (!take) take = 1;
    advance(L, take);
    (void)try_match;  /* unused helper kept for future use */

    cfmt_tok_t t;
    fill_span(&t, TOK_PUNCT, L, m);
    return push_tok(L, &t);
}

/* --- Top-level dispatch --------------------------------------------------- */

/* Look ahead from L->p to see if we have a wide-string/char prefix followed
   by " or '. If so, set *enc and *advance_n. Otherwise *advance_n = 0. */
static void detect_enc_prefix(const lexer_t *L, cfmt_enc_t *enc, size_t *advance_n) {
    *enc = CFMT_ENC_NONE;
    *advance_n = 0;
    if (L->p >= L->end) return;
    int c0 = (unsigned char)L->p[0];
    int c1 = lex_peek(L, 1);
    int c2 = lex_peek(L, 2);

    if (c0 == 'L' && (c1 == '"' || c1 == '\'')) {
        *enc = CFMT_ENC_L; *advance_n = 1;
    } else if (c0 == 'U' && (c1 == '"' || c1 == '\'')) {
        *enc = CFMT_ENC_U; *advance_n = 1;
    } else if (c0 == 'u' && c1 == '8' && c2 == '"') {
        *enc = CFMT_ENC_u8; *advance_n = 2;
    } else if (c0 == 'u' && (c1 == '"' || c1 == '\'')) {
        *enc = CFMT_ENC_u; *advance_n = 1;
    }
}

ds_status_t cfmt_lex(const char        *source,
                     size_t             source_len,
                     ds_context_t      *ctx,
                     ds_arena_t        *arena,
                     cfmt_tok_stream_t *out) {
    lexer_t L;
    L.p          = source;
    L.end        = source + source_len;
    L.line       = 1;
    L.col        = 1;
    L.line_start = 1;
    L.out        = out;
    L.out->ctx   = ctx;
    L.out->arena = arena;
    L.out->source = source;
    L.out->source_len = source_len;
    L.out->tokens = NULL;
    L.out->count  = 0;
    L.out->cap    = 0;
    (void)arena;

    while (L.p < L.end) {
        int c = (unsigned char)*L.p;
        int line_start_was = L.line_start;
        ds_status_t st = DS_OK;

        if (is_hspace(c)) {
            st = lex_whitespace(&L);
            /* line_start preserved */
        } else if (c == '\n') {
            st = lex_newline(&L);
        } else if (c == '/' && lex_peek(&L, 1) == '/') {
            st = lex_line_comment(&L);
            L.line_start = 0;
        } else if (c == '/' && lex_peek(&L, 1) == '*') {
            st = lex_block_comment(&L);
            L.line_start = 0;
        } else if (c == '#' && line_start_was) {
            st = lex_pp_directive(&L);
            L.line_start = 0;
        } else if (is_digit(c) || (c == '.' && is_digit(lex_peek(&L, 1)))) {
            st = lex_number(&L);
            L.line_start = 0;
        } else {
            cfmt_enc_t enc;
            size_t pref_n;
            detect_enc_prefix(&L, &enc, &pref_n);
            if (pref_n > 0) {
                mark_t m = take_mark(&L);
                advance(&L, pref_n);
                int q = (unsigned char)*L.p;
                if (q == '"')       st = lex_string_lit(&L, enc, m);
                else if (q == '\'') st = lex_char_lit(&L, enc, m);
                else                st = DS_ERR_INTERNAL;  /* unreachable */
                L.line_start = 0;
            } else if (is_id_start(c)) {
                st = lex_ident(&L);
                L.line_start = 0;
            } else if (c == '"') {
                mark_t m = take_mark(&L);
                st = lex_string_lit(&L, CFMT_ENC_NONE, m);
                L.line_start = 0;
            } else if (c == '\'') {
                mark_t m = take_mark(&L);
                st = lex_char_lit(&L, CFMT_ENC_NONE, m);
                L.line_start = 0;
            } else {
                st = lex_punct(&L);
                L.line_start = 0;
            }
        }

        if (st != DS_OK) return st;
    }

    /* Emit EOF sentinel. */
    cfmt_tok_t eof;
    memset(&eof, 0, sizeof(eof));
    eof.kind   = TOK_EOF;
    eof.lexeme = L.p;
    eof.line   = L.line;
    eof.col    = L.col;
    return push_tok(&L, &eof);
}

/* --- Convenience checks --------------------------------------------------- */

int cfmt_tok_is_punct(const cfmt_tok_t *t, const char *punct) {
    if (!t || t->kind != TOK_PUNCT) return 0;
    size_t n = strlen(punct);
    return t->lexeme_len == n && memcmp(t->lexeme, punct, n) == 0;
}

int cfmt_tok_is_ident(const cfmt_tok_t *t, const char *ident) {
    if (!t || t->kind != TOK_IDENT) return 0;
    size_t n = strlen(ident);
    return t->lexeme_len == n && memcmp(t->lexeme, ident, n) == 0;
}

/* ============================================================
 * ast.c
 * ============================================================
 */
/*
 * ast.c — AST node helpers. The parser proper lives in parser.c.
 */



const char *cfmt_ast_kind_name(cfmt_ast_kind_t k) {
    switch (k) {
        case AST_TRANSLATION_UNIT: return "TU";
        case AST_PP_DIRECTIVE:     return "PP";
        case AST_DECL:             return "DECL";
        case AST_FUNC_DEF:         return "FUNC_DEF";
        case AST_BLOCK:            return "BLOCK";
        case AST_UNKNOWN:          return "UNKNOWN";
    }
    return "?";
}

int cfmt_ast_walk(cfmt_ast_t *root,
                  int (*visit)(cfmt_ast_t *node, void *user),
                  void *user) {
    if (!root) return 0;
    int rc = visit(root, user);
    if (rc) return rc;
    for (cfmt_ast_t *c = root->first_child; c; c = c->next_sibling) {
        rc = cfmt_ast_walk(c, visit, user);
        if (rc) return rc;
    }
    return 0;
}

cfmt_ast_t *cfmt_ast_enclosing_func(cfmt_ast_t *node) {
    for (cfmt_ast_t *p = node; p; p = p->parent) {
        if (p->kind == AST_FUNC_DEF) return p;
    }
    return NULL;
}

static void dump_node(cfmt_ast_t *n, const cfmt_tok_stream_t *stream,
                      FILE *out, int depth) {
    for (int i = 0; i < depth; i++) fputs("  ", out);
    fprintf(out, "(%s [%zu..%zu)", cfmt_ast_kind_name(n->kind),
            n->first_tok_idx, n->last_tok_idx);
    if (n->kind == AST_PP_DIRECTIVE && n->first_tok_idx < stream->count) {
        const cfmt_tok_t *t = &stream->tokens[n->first_tok_idx];
        /* Show first line of the directive. */
        size_t len = t->lexeme_len;
        if (len > 40) len = 40;
        fputs(" \"", out);
        for (size_t i = 0; i < len; i++) {
            char c = t->lexeme[i];
            if (c == '\n') break;
            fputc((c < 32 || c == '"') ? '?' : c, out);
        }
        fputc('"', out);
    }
    if (!n->first_child) {
        fputs(")\n", out);
        return;
    }
    fputs("\n", out);
    for (cfmt_ast_t *c = n->first_child; c; c = c->next_sibling) {
        dump_node(c, stream, out, depth + 1);
    }
    for (int i = 0; i < depth; i++) fputs("  ", out);
    fputs(")\n", out);
}

void cfmt_ast_dump(cfmt_ast_t *root, const cfmt_tok_stream_t *stream, FILE *out) {
    dump_node(root, stream, out, 0);
}

/* ============================================================
 * parser.c
 * ============================================================
 */
/*
 * parser.c — build a coarse AST from a token stream.
 *
 * Top level (cfmt_parse):
 *   { parse_top_level }* until EOF
 *
 * parse_top_level returns one of:
 *   - AST_PP_DIRECTIVE: a single TOK_PP_DIRECTIVE token
 *   - AST_DECL:         tokens up to and including the first `;` at paren
 *                       depth 0 (including any struct/union/enum bodies
 *                       found along the way)
 *   - AST_FUNC_DEF:     tokens up to and including the matching `}` of the
 *                       function body, where the body opened with `{`
 *                       immediately after a `)` at paren depth 0
 *   - AST_UNKNOWN:      anything we couldn't classify
 *
 * Inside a function body, parse_block walks nested `{` ... `}` regions and
 * builds AST_BLOCK children. Everything else (statements, expressions)
 * is implicit in the parent block's token range — we don't model
 * statements individually.
 *
 * Comments, whitespace, and newlines are tokens. They are part of the parent
 * range but never "significant" for classification.
 */



/* ----- Parser state ------------------------------------------------------- */

typedef struct {
    cfmt_tok_stream_t *stream;
    ds_context_t      *ctx;
    size_t             i;     /* current token index */
} parser_t;

static cfmt_ast_t *new_node(parser_t *P, cfmt_ast_kind_t kind, size_t first) {
    cfmt_ast_t *n = (cfmt_ast_t *)ds_context_alloc(P->ctx, sizeof(*n));
    if (!n) return NULL;
    memset(n, 0, sizeof(*n));
    n->kind            = kind;
    n->first_tok_idx   = first;
    n->last_tok_idx    = first;
    n->open_brace_idx  = (size_t)-1;
    n->close_brace_idx = (size_t)-1;
    return n;
}

static void append_child(cfmt_ast_t *parent, cfmt_ast_t *child) {
    child->parent = parent;
    if (parent->last_child) {
        parent->last_child->next_sibling = child;
    } else {
        parent->first_child = child;
    }
    parent->last_child = child;
}

static const cfmt_tok_t *par_peek(parser_t *P) {
    return &P->stream->tokens[P->i];
}

static int at_end(parser_t *P) {
    return P->stream->tokens[P->i].kind == TOK_EOF;
}

/* True if the token kind is "significant": affects classification. */
static int par_is_significant(cfmt_tok_kind_t k) {
    return k != TOK_WHITESPACE &&
           k != TOK_NEWLINE    &&
           k != TOK_COMMENT_LINE &&
           k != TOK_COMMENT_BLOCK;
}

/* (next_sig_idx removed; classify() walks inline.) */


/* ----- Block parsing ------------------------------------------------------ */

/* parse_block — caller has positioned P->i AT a `{` punct. Consumes through
   the matching `}`. Returns AST_BLOCK or NULL on allocation failure. */
static cfmt_ast_t *parse_block(parser_t *P) {
    size_t open = P->i;
    cfmt_ast_t *block = new_node(P, AST_BLOCK, open);
    if (!block) return NULL;
    block->open_brace_idx = open;
    P->i++;  /* consume { */

    while (!at_end(P)) {
        const cfmt_tok_t *t = par_peek(P);

        if (cfmt_tok_is_punct(t, "}")) {
            block->close_brace_idx = P->i;
            P->i++;
            block->last_tok_idx = P->i;
            return block;
        }
        if (cfmt_tok_is_punct(t, "{")) {
            cfmt_ast_t *nested = parse_block(P);
            if (!nested) return NULL;
            append_child(block, nested);
            continue;
        }
        if (t->kind == TOK_PP_DIRECTIVE) {
            cfmt_ast_t *pp = new_node(P, AST_PP_DIRECTIVE, P->i);
            if (!pp) return NULL;
            P->i++;
            pp->last_tok_idx = P->i;
            append_child(block, pp);
            continue;
        }
        P->i++;
    }

    /* Unterminated block — close it where we ended. */
    block->last_tok_idx = P->i;
    return block;
}

/* ----- Top-level parsing -------------------------------------------------- */

/* Scan forward from start to classify the next top-level entity.
 * The classification is based on what punctuator we hit first at paren
 * depth 0 (ignoring tokens inside `{...}` brace-init bodies):
 *   - `;`             → DECL
 *   - `{` after `)`   → FUNC_DEF
 *   - `{` otherwise   → DECL with a brace body (struct/union/enum/init)
 *   - EOF             → UNKNOWN
 * On return, *p_body_open points at the `{` if FUNC_DEF (else SIZE_MAX).
 * *p_end is the index of the terminating `;` or `}` (inclusive). */
static cfmt_ast_kind_t classify(parser_t *P, size_t start,
                                size_t *p_body_open, size_t *p_end) {
    *p_body_open = (size_t)-1;
    *p_end       = (size_t)-1;

    int paren_depth = 0;
    size_t last_sig = (size_t)-1;
    size_t i = start;
    const cfmt_tok_stream_t *s = P->stream;

    while (i < s->count) {
        const cfmt_tok_t *t = &s->tokens[i];
        if (t->kind == TOK_EOF) break;
        if (!par_is_significant(t->kind)) { i++; continue; }

        if (cfmt_tok_is_punct(t, "(")) {
            paren_depth++;
            last_sig = i;
            i++;
            continue;
        }
        if (cfmt_tok_is_punct(t, ")")) {
            if (paren_depth > 0) paren_depth--;
            last_sig = i;
            i++;
            continue;
        }
        if (paren_depth == 0 && cfmt_tok_is_punct(t, ";")) {
            *p_end = i;
            return AST_DECL;
        }
        if (paren_depth == 0 && cfmt_tok_is_punct(t, "{")) {
            /* Function body iff previous significant token was ) */
            int is_func = 0;
            if (last_sig != (size_t)-1 &&
                cfmt_tok_is_punct(&s->tokens[last_sig], ")")) {
                is_func = 1;
            }
            if (is_func) {
                *p_body_open = i;
                /* Find matching }. */
                size_t j = i + 1;
                int depth = 1;
                while (j < s->count && depth > 0) {
                    const cfmt_tok_t *u = &s->tokens[j];
                    if (cfmt_tok_is_punct(u, "{")) depth++;
                    else if (cfmt_tok_is_punct(u, "}")) depth--;
                    j++;
                }
                *p_end = (depth == 0) ? (j - 1) : j;
                return AST_FUNC_DEF;
            }
            /* Brace-init or struct/union/enum body — skip to matching }. */
            size_t j = i + 1;
            int depth = 1;
            while (j < s->count && depth > 0) {
                const cfmt_tok_t *u = &s->tokens[j];
                if (cfmt_tok_is_punct(u, "{")) depth++;
                else if (cfmt_tok_is_punct(u, "}")) depth--;
                j++;
            }
            i = j;
            last_sig = (j > 0) ? (j - 1) : 0;
            continue;
        }
        last_sig = i;
        i++;
    }
    *p_end = (i < s->count) ? i : (s->count - 1);
    return AST_UNKNOWN;
}

/* Parse one top-level entity, append to parent, advance P->i. */
static int parse_top_level(parser_t *P, cfmt_ast_t *parent) {
    const cfmt_tok_t *t = par_peek(P);

    /* Skip leading non-significant tokens — they belong to whatever follows.
       (For now we attach them to the next entity by starting its range at
       the same position; this keeps the AST losslessly cover all tokens.) */

    if (t->kind == TOK_PP_DIRECTIVE) {
        cfmt_ast_t *pp = new_node(P, AST_PP_DIRECTIVE, P->i);
        if (!pp) return -1;
        P->i++;
        pp->last_tok_idx = P->i;
        append_child(parent, pp);
        return 0;
    }

    /* Skip whitespace/newlines/comments — they'll be absorbed by the next
       significant entity. */
    if (!par_is_significant(t->kind)) {
        /* Create a tiny AST_UNKNOWN that covers just this token so the tree
           still spans every token (useful for emit). */
        cfmt_ast_t *u = new_node(P, AST_UNKNOWN, P->i);
        if (!u) return -1;
        P->i++;
        u->last_tok_idx = P->i;
        append_child(parent, u);
        return 0;
    }

    size_t start = P->i;
    size_t body_open, end_idx;
    cfmt_ast_kind_t k = classify(P, start, &body_open, &end_idx);

    if (k == AST_DECL) {
        cfmt_ast_t *decl = new_node(P, AST_DECL, start);
        if (!decl) return -1;
        P->i = end_idx + 1;  /* past the ; */
        decl->last_tok_idx = P->i;
        append_child(parent, decl);
        return 0;
    }

    if (k == AST_FUNC_DEF) {
        cfmt_ast_t *fn = new_node(P, AST_FUNC_DEF, start);
        if (!fn) return -1;
        fn->open_brace_idx  = body_open;
        fn->close_brace_idx = end_idx;
        /* Jump to body open, parse_block, then we should be at end_idx+1. */
        P->i = body_open;
        cfmt_ast_t *body = parse_block(P);
        if (!body) return -1;
        append_child(fn, body);
        fn->last_tok_idx = P->i;
        append_child(parent, fn);
        return 0;
    }

    /* AST_UNKNOWN: consume to end_idx + 1 to make progress. */
    cfmt_ast_t *u = new_node(P, AST_UNKNOWN, start);
    if (!u) return -1;
    P->i = end_idx + 1;
    if (P->i <= start) P->i = start + 1;
    u->last_tok_idx = P->i;
    append_child(parent, u);
    return 0;
}

/* ----- Public entry ------------------------------------------------------- */

cfmt_ast_t *cfmt_parse(cfmt_tok_stream_t *stream, ds_context_t *ctx) {
    parser_t P;
    P.stream = stream;
    P.ctx    = ctx;
    P.i      = 0;

    cfmt_ast_t *tu = new_node(&P, AST_TRANSLATION_UNIT, 0);
    if (!tu) return NULL;

    while (!at_end(&P)) {
        if (parse_top_level(&P, tu) != 0) return NULL;
    }
    tu->last_tok_idx = P.i;
    return tu;
}

/* ============================================================
 * pass_destring.c
 * ============================================================
 */
/*
 * pass_destring.c — string-literal lift-and-rename pass.
 *
 * For every TOK_STRING_LIT we plan a replacement:
 *   - If the run of adjacent string literals (single logical literal in C
 *     terms) sits in array-initializer context (` ... ] = "..."`), the
 *     first token is replaced with a brace-initializer `{b,b,...,0}` and
 *     subsequent tokens in the run are omitted.
 *   - Otherwise, the run is replaced with a reference to a generated
 *     variable `sXXXXXXXX` (FNV-1a hex hash), declared once at the start
 *     of its enclosing function (or as a `static const char` array at file
 *     scope if it appears outside any function).
 *
 * Adjacent strings sharing an encoding prefix (plain / L / u / U / u8) are
 * concatenated. Mixed-prefix runs are left alone (rare; the program punts).
 *
 * For every plain (encoding-NONE) TOK_CHAR_LIT we plan a CHAR_NUM action so
 * the emitter writes the decimal value instead of the quoted character.
 */



/* --- FNV-1a 32-bit --------------------------------------------------------- */

unsigned int cfmt_fnv1a(const unsigned char *data, size_t n) {
    unsigned int h = 2166136261u;
    for (size_t i = 0; i < n; i++) {
        h ^= data[i];
        h *= 16777619u;
    }
    return h;
}

/* --- Literal tables ------------------------------------------------------- */

static ds_status_t lit_table_init(cfmt_lit_table_t *t, ds_context_t *ctx) {
    memset(t, 0, sizeof(*t));
    t->ctx = ctx;
    t->by_hash = ds_string_map_create_ctx(ctx);
    if (!t->by_hash) return DS_ERR_ALLOC;
    return DS_OK;
}

/* Intern `bytes`/`byte_count` into `t`. If an entry with the same hash is
 * already present, returns it. Otherwise allocates a new entry and adds it. */
static cfmt_lit_entry_t *lit_table_intern(cfmt_lit_table_t *t,
                                          const unsigned char *bytes,
                                          size_t byte_count) {
    unsigned int hash = cfmt_fnv1a(bytes, byte_count);

    /* Key = hex representation of the hash. */
    char key[16];
    snprintf(key, sizeof(key), "%08x", hash);

    /* Look up. ds_string_map_get returns DS_OK with non-NULL value on hit,
       DS_NOT_FOUND otherwise. */
    void *existing = NULL;
    if (ds_string_map_get(t->by_hash, key, &existing) == DS_OK && existing) {
        return (cfmt_lit_entry_t *)existing;
    }

    /* Create new entry. */
    cfmt_lit_entry_t *e = (cfmt_lit_entry_t *)ds_context_alloc(t->ctx, sizeof(*e));
    if (!e) return NULL;
    e->hash = hash;
    e->byte_count = byte_count;
    if (byte_count > 0) {
        e->bytes = (unsigned char *)ds_context_alloc(t->ctx, byte_count);
        if (!e->bytes) return NULL;
        memcpy(e->bytes, bytes, byte_count);
    } else {
        e->bytes = NULL;
    }

    /* Push into ordered array. */
    if (t->count >= t->cap) {
        size_t newcap = t->cap ? t->cap * 2 : 16;
        cfmt_lit_entry_t **nb = (cfmt_lit_entry_t **)realloc(
            t->entries, newcap * sizeof(cfmt_lit_entry_t *));
        if (!nb) return NULL;
        t->entries = nb;
        t->cap = newcap;
    }
    t->entries[t->count++] = e;

    /* Insert into hash dedup map (key is strdup'd internally). */
    if (ds_string_map_put(t->by_hash, key, e) != DS_OK) return NULL;

    return e;
}

/* --- Pass result allocation ----------------------------------------------- */

ds_status_t cfmt_pass_result_init(cfmt_pass_result_t *r,
                                  cfmt_tok_stream_t *stream,
                                  ds_context_t      *ctx) {
    memset(r, 0, sizeof(*r));
    r->ctx = ctx;
    if (lit_table_init(&r->file_lits, ctx) != DS_OK) return DS_ERR_ALLOC;
    r->actions = (cfmt_action_t *)calloc(stream->count, sizeof(cfmt_action_t));
    if (!r->actions) return DS_ERR_ALLOC;
    r->actions_count = stream->count;
    return DS_OK;
}

/* --- Helpers --------------------------------------------------------------- */

static int pd_is_significant(cfmt_tok_kind_t k) {
    return k != TOK_WHITESPACE &&
           k != TOK_NEWLINE    &&
           k != TOK_COMMENT_LINE &&
           k != TOK_COMMENT_BLOCK;
}

/* True iff the declarator immediately before `eq_idx` (the `=`) is
 * pointer-like — i.e., contains an unmatched `*` at brace-depth 0 between
 * the previous declaration boundary (`;` or `,` at depth 0) and `eq_idx`.
 * This lets us tell apart:
 *
 *   char arr[]   = { ... }         no `*`           → BRACE_INIT
 *   char *p      = { ... }         `*` at depth 0   → VAR_REF
 *   char *a[]    = { "...", ...}   `*` at depth 0   → VAR_REF
 *   struct X x   = { ... }         no `*` at d0     → BRACE_INIT
 *   struct{char *p;} s = {...}     `*` only inside  → BRACE_INIT (limit)
 *                                  the struct body
 *
 * Brace-depth 0 means we skip over the contents of struct/union/enum
 * definitions like `struct {char *p;}`, which can contain `*` belonging to
 * fields, not to the outer variable. */
static int declarator_is_pointer(const cfmt_tok_stream_t *s, long eq_idx) {
    /* Walk back from eq_idx-1 until hitting `;` or `,` at top brace and
       paren depth, marking that point as `start`. */
    long start = eq_idx - 1;
    int brace = 0;
    int paren = 0;
    while (start >= 0) {
        const cfmt_tok_t *t = &s->tokens[start];
        if (!pd_is_significant(t->kind)) { start--; continue; }
        if (cfmt_tok_is_punct(t, "}")) { brace++; start--; continue; }
        if (cfmt_tok_is_punct(t, ")")) { paren++; start--; continue; }
        if (cfmt_tok_is_punct(t, "{")) {
            if (brace > 0) { brace--; start--; continue; }
            /* Hit an enclosing { — stop. */
            start++;
            break;
        }
        if (cfmt_tok_is_punct(t, "(")) {
            if (paren > 0) { paren--; start--; continue; }
            start++;
            break;
        }
        if (brace == 0 && paren == 0 &&
            (cfmt_tok_is_punct(t, ";") || cfmt_tok_is_punct(t, ","))) {
            start++;
            break;
        }
        start--;
    }
    if (start < 0) start = 0;

    /* Now scan forward from start to eq_idx looking for `*` at brace-depth 0
       and paren-depth 0. */
    brace = 0; paren = 0;
    for (long i = start; i < eq_idx; i++) {
        const cfmt_tok_t *t = &s->tokens[i];
        if (!pd_is_significant(t->kind)) continue;
        if (cfmt_tok_is_punct(t, "{")) { brace++; continue; }
        if (cfmt_tok_is_punct(t, "}")) { if (brace) brace--; continue; }
        if (cfmt_tok_is_punct(t, "(")) { paren++; continue; }
        if (cfmt_tok_is_punct(t, ")")) { if (paren) paren--; continue; }
        if (brace == 0 && paren == 0 && cfmt_tok_is_punct(t, "*")) {
            return 1;
        }
    }
    return 0;
}

/* Decide whether a string literal at index `i` is in an "init context" —
 * meaning the destringer should expand it as a brace initializer in place
 * (so the surrounding aggregate/array assignment continues to work).
 *
 * Returns:
 *   0 — not init context; emit as VAR_REF (default)
 *   1 — array/aggregate init context AND the declarator isn't pointer-like;
 *       emit as BRACE_INIT
 *
 * The two patterns we recognize as init contexts:
 *
 *   (a) Direct array init:  T name [N] = STRING  /  T name [] = STRING
 *       Walking backward from STRING through significant tokens, the first
 *       is `=`, and `]` appears before any boundary token (`;`/`,`/`(`/`{`).
 *
 *   (b) Inside a (possibly nested) brace initializer:
 *           T name = { ..., STRING, ... }
 *           T arr[] = { {...}, {STRING}, ... }
 *           struct {char buf[N];} s = {STRING, ...};
 *       Walking backward we cross `{`s whose immediate predecessor is `=` or
 *       another `{`/`,` of an enclosing init brace. paren_depth and
 *       brace_depth track nesting along the way.
 *
 * Once we find the anchoring `=`, we inspect the declarator before it for a
 * top-level `*` (declarator_is_pointer). If the variable being initialized
 * is pointer-like, we return 0 so the literal is lifted as a separate
 * named array and the original `{ ... }` slots become pointer references —
 * preserving the original semantics. */
static int looks_like_array_init(const cfmt_tok_stream_t *s, size_t i) {
    long j = (long)i - 1;
    int brace_depth = 0;
    int paren_depth = 0;

    while (j >= 0) {
        cfmt_tok_kind_t k = s->tokens[j].kind;
        if (!pd_is_significant(k)) { j--; continue; }
        const cfmt_tok_t *t = &s->tokens[j];

        if (cfmt_tok_is_punct(t, "}")) { brace_depth++; j--; continue; }
        if (cfmt_tok_is_punct(t, ")")) { paren_depth++; j--; continue; }

        if (cfmt_tok_is_punct(t, "{")) {
            if (brace_depth > 0) { brace_depth--; j--; continue; }
            /* Enclosing `{`. Check what came right before. */
            long p = j - 1;
            while (p >= 0 && !pd_is_significant(s->tokens[p].kind)) p--;
            if (p < 0) return 0;
            const cfmt_tok_t *prev = &s->tokens[p];
            if (cfmt_tok_is_punct(prev, "=")) {
                /* Anchor `=` is at index p. Decide based on declarator. */
                return declarator_is_pointer(s, p) ? 0 : 1;
            }
            if (cfmt_tok_is_punct(prev, "{") ||
                cfmt_tok_is_punct(prev, ",")) {
                /* Nested init brace; continue walking back past this `{`. */
                j = p;
                continue;
            }
            return 0;
        }

        if (cfmt_tok_is_punct(t, "(")) {
            if (paren_depth > 0) { paren_depth--; j--; continue; }
            return 0;  /* inside parens (call/decl), not init */
        }

        if (cfmt_tok_is_punct(t, "=") && brace_depth == 0 && paren_depth == 0) {
            /* Direct `... = STRING` pattern: array iff `]` before a boundary
               AND the declarator isn't pointer-like. */
            long p = j - 1;
            int saw_bracket = 0;
            while (p >= 0) {
                if (!pd_is_significant(s->tokens[p].kind)) { p--; continue; }
                const cfmt_tok_t *u = &s->tokens[p];
                if (cfmt_tok_is_punct(u, "]")) { saw_bracket = 1; break; }
                if (cfmt_tok_is_punct(u, ";") ||
                    cfmt_tok_is_punct(u, ",") ||
                    cfmt_tok_is_punct(u, "(") ||
                    cfmt_tok_is_punct(u, "{")) break;
                p--;
            }
            if (!saw_bracket) return 0;
            return declarator_is_pointer(s, j) ? 0 : 1;
        }

        if (cfmt_tok_is_punct(t, ";") && brace_depth == 0 && paren_depth == 0) {
            return 0;  /* statement boundary; not in init */
        }

        j--;
    }
    return 0;
}

/* Find the maximal adjacent-string run starting at index `i` and sharing the
 * encoding of stream->tokens[i]. Returns the index one past the last
 * STRING_LIT token in the run (note: this is NOT the same as "past the last
 * token", because there may be insignificant tokens after). */
static size_t adjacent_string_run_end(const cfmt_tok_stream_t *s, size_t i) {
    cfmt_enc_t enc = s->tokens[i].u.str.enc;
    size_t last_string = i;
    size_t j = i + 1;
    while (j < s->count) {
        cfmt_tok_kind_t k = s->tokens[j].kind;
        if (k == TOK_STRING_LIT) {
            if (s->tokens[j].u.str.enc != enc) break;
            last_string = j;
            j++;
            continue;
        }
        if (pd_is_significant(k) || k == TOK_PP_DIRECTIVE) break;
        j++;
    }
    return last_string + 1;  /* half-open past the last STRING_LIT */
}

/* --- Function-table bookkeeping ------------------------------------------- */

/* Allocate the next per-function literal table slot, return a pointer to it. */
static cfmt_lit_table_t *next_func_table(cfmt_pass_result_t *r) {
    if (r->func_lits_count >= r->func_lits_cap) {
        size_t newcap = r->func_lits_cap ? r->func_lits_cap * 2 : 8;
        cfmt_lit_table_t *nb = (cfmt_lit_table_t *)realloc(
            r->func_lits, newcap * sizeof(cfmt_lit_table_t));
        if (!nb) return NULL;
        r->func_lits = nb;
        r->func_lits_cap = newcap;
    }
    cfmt_lit_table_t *slot = &r->func_lits[r->func_lits_count++];
    if (lit_table_init(slot, r->ctx) != DS_OK) {
        r->func_lits_count--;
        return NULL;
    }
    return slot;
}

/* --- Token-range processing ---------------------------------------------- */

typedef struct {
    cfmt_tok_stream_t  *stream;
    cfmt_pass_result_t *result;
} ctx_t;

/* Process tokens in [start, end) that belong directly to this AST node
   (i.e., not owned by a deeper child). `active_table` is the lit table for
   the enclosing scope. */
static int process_own_tokens(ctx_t *C, cfmt_ast_t *node,
                              cfmt_lit_table_t *active_table) {
    size_t i = node->first_tok_idx;
    /* Iterate but skip the ranges of children. */
    while (i < node->last_tok_idx) {
        /* If this token is inside a child, skip past that child. */
        cfmt_ast_t *into_child = NULL;
        for (cfmt_ast_t *c = node->first_child; c; c = c->next_sibling) {
            if (i >= c->first_tok_idx && i < c->last_tok_idx) {
                into_child = c;
                break;
            }
        }
        if (into_child) { i = into_child->last_tok_idx; continue; }

        cfmt_tok_t *t = &C->stream->tokens[i];

        if (t->kind == TOK_STRING_LIT) {
            /* Wide-encoding strings: leave alone (would need wchar / utf16/32
               handling). */
            if (t->u.str.enc != CFMT_ENC_NONE) { i++; continue; }

            size_t run_end = adjacent_string_run_end(C->stream, i);
            /* Concat bytes of every STRING_LIT in [i, run_end). */
            size_t total = 0;
            for (size_t k = i; k < run_end; k++) {
                if (C->stream->tokens[k].kind == TOK_STRING_LIT) {
                    total += C->stream->tokens[k].u.str.byte_count;
                }
            }
            unsigned char *concat = NULL;
            if (total > 0) {
                concat = (unsigned char *)ds_context_alloc(C->result->ctx, total);
                if (!concat) return -1;
                size_t off = 0;
                for (size_t k = i; k < run_end; k++) {
                    if (C->stream->tokens[k].kind == TOK_STRING_LIT) {
                        memcpy(concat + off,
                               C->stream->tokens[k].u.str.bytes,
                               C->stream->tokens[k].u.str.byte_count);
                        off += C->stream->tokens[k].u.str.byte_count;
                    }
                }
            }

            int array_init = looks_like_array_init(C->stream, i);
            cfmt_lit_entry_t *e = lit_table_intern(active_table, concat, total);
            if (!e) return -1;

            C->result->actions[i].kind =
                array_init ? CFMT_ACT_BRACE_INIT : CFMT_ACT_VAR_REF;
            C->result->actions[i].entry = e;

            /* Mark trailing string tokens in the run as OMIT. */
            for (size_t k = i + 1; k < run_end; k++) {
                if (C->stream->tokens[k].kind == TOK_STRING_LIT) {
                    C->result->actions[k].kind = CFMT_ACT_OMIT;
                }
            }
            i = run_end;
            continue;
        }

        if (t->kind == TOK_CHAR_LIT && t->u.chr.enc == CFMT_ENC_NONE) {
            C->result->actions[i].kind = CFMT_ACT_CHAR_NUM;
        }
        i++;
    }
    return 0;
}

/* Recursive walk: maintain the active table; create a new one per FUNC_DEF. */
static int walk(ctx_t *C, cfmt_ast_t *node, cfmt_lit_table_t *active) {
    cfmt_lit_table_t *here = active;

    if (node->kind == AST_FUNC_DEF) {
        here = next_func_table(C->result);
        if (!here) return -1;
    }

    if (process_own_tokens(C, node, here) != 0) return -1;

    for (cfmt_ast_t *c = node->first_child; c; c = c->next_sibling) {
        if (walk(C, c, here) != 0) return -1;
    }
    return 0;
}

/* --- Entry point ---------------------------------------------------------- */

ds_status_t cfmt_pass_destring(cfmt_ast_t        *root,
                               cfmt_tok_stream_t *stream,
                               cfmt_pass_result_t *result) {
    ctx_t C;
    C.stream = stream;
    C.result = result;
    if (walk(&C, root, &result->file_lits) != 0) return DS_ERR_ALLOC;
    return DS_OK;
}

/* ============================================================
 * emit.c
 * ============================================================
 */
/*
 * emit.c — produce unaligned post-transformation text.
 *
 * The output is later fed to the aligner, which makes every line exactly
 * 80 characters wide.
 */



/* --- Output helpers ------------------------------------------------------ */

static int put_bytes(ds_str_t *out, const char *data, size_t n) {
    return str_append(out, data, n);
}
static int put_cstr(ds_str_t *out, const char *s) {
    return str_append_cstr(out, s);
}
static int put_fmt(ds_str_t *out, const char *fmt, ...) {
    va_list ap; va_start(ap, fmt);
    int rc = str_append_vfmt(out, fmt, ap);
    va_end(ap);
    return rc;
}

/* Emit the "var name" form of a literal entry: sXXXXXXXX (8 hex). */
static int put_varname(ds_str_t *out, const cfmt_lit_entry_t *e) {
    return put_fmt(out, "s%08x", e->hash);
}

/* --- File-scope literal declarations ------------------------------------- */
/*
 *   static const char sXXX[N]={
 *   b0,
 *   b1,
 *   ...
 *   0};
 *
 * The array's length includes the null terminator.
 */
static int emit_file_scope_decl(ds_str_t *out, const cfmt_lit_entry_t *e) {
    size_t total = e->byte_count + 1;  /* +1 for null terminator */
    int rc = 0;
    rc |= put_fmt(out, "static const char s%08x[%zu]={\n", e->hash, total);
    for (size_t i = 0; i < e->byte_count; i++) {
        rc |= put_fmt(out, "%u,\n", (unsigned)e->bytes[i]);
    }
    rc |= put_cstr(out, "0};\n");
    return rc;
}

/* --- Function-scope literal declaration ---------------------------------- */
/*
 * For VAR_REF use inside a function we emit:
 *
 *   static const char sXXX[N]={
 *   b0,
 *   b1,
 *   ...
 *   0};
 *
 * `static const` is critical for two reasons:
 *   - lifetime: a string literal in C has static storage duration; a code
 *     path that returns or stashes a pointer to it must continue to work
 *     after the transformation. A non-static function-local `char[]` would
 *     dangle after return.
 *   - correctness for unique-instance semantics: making it const matches
 *     the original literal (writing to a string literal is UB).
 *
 * Each element is on its own line so the aligner can format each at 80
 * chars wide.
 */
static int emit_func_scope_decl(ds_str_t *out, const cfmt_lit_entry_t *e) {
    size_t total = e->byte_count + 1;
    int rc = 0;
    rc |= put_fmt(out, "static const char s%08x[%zu]={\n", e->hash, total);
    for (size_t i = 0; i < e->byte_count; i++) {
        rc |= put_fmt(out, "%u,\n", (unsigned)e->bytes[i]);
    }
    rc |= put_cstr(out, "0};\n");
    return rc;
}

/* --- In-place brace-init expansion --------------------------------------- */
/*
 * Replaces a STRING_LIT token in array-init context:
 *
 *   {
 *   b0,
 *   b1,
 *   ...
 *   0}
 *
 * The opening `{` is on its own line so it joins the previous token's line
 * (typical context: `char arr[]={`). The closing `}` is on the last byte's
 * line. Surrounding `;` (or `,`) comes from the next token.
 */
static int emit_brace_init(ds_str_t *out, const cfmt_lit_entry_t *e) {
    int rc = 0;
    rc |= put_cstr(out, "{\n");
    for (size_t i = 0; i < e->byte_count; i++) {
        rc |= put_fmt(out, "%u,\n", (unsigned)e->bytes[i]);
    }
    rc |= put_cstr(out, "0}");
    return rc;
}

/* --- Per-token emission -------------------------------------------------- */

static int emit_token(ds_str_t *out, const cfmt_tok_t *t, const cfmt_action_t *a) {
    /* Comments are stripped entirely. The aligner is destructive by
       construction — string literals become byte arrays, character literals
       become decimal numbers — and leaving comments would jar against that
       aesthetic. The surrounding whitespace/newline tokens stay, so a
       full-line comment becomes a blank line. */
    if (t->kind == TOK_COMMENT_LINE || t->kind == TOK_COMMENT_BLOCK) {
        return 0;
    }
    switch (a->kind) {
        case CFMT_ACT_NONE:
            return put_bytes(out, t->lexeme, t->lexeme_len);
        case CFMT_ACT_VAR_REF:
            return put_varname(out, a->entry);
        case CFMT_ACT_BRACE_INIT:
            return emit_brace_init(out, a->entry);
        case CFMT_ACT_CHAR_NUM:
            return put_fmt(out, "%lu", t->u.chr.value);
        case CFMT_ACT_OMIT:
            return 0;
    }
    return 0;
}

/* --- Walk the AST -------------------------------------------------------- */

typedef struct {
    cfmt_tok_stream_t  *stream;
    cfmt_pass_result_t *result;
    ds_str_t           *out;
    size_t              func_index;
} emit_ctx_t;

/* Emit all tokens in [start, end) that are *own tokens* of `node` (i.e., not
   in any child's range). Walks the slice; for each token, either applies its
   action or recurses into the child that contains it.

   If `node` is a function body (i.e., a BLOCK whose parent is a FUNC_DEF),
   we inject the function-scope literal preamble right after emitting the
   opening `{`. */
static int emit_node(emit_ctx_t *C, cfmt_ast_t *node) {
    int is_func_body =
        node->kind == AST_BLOCK &&
        node->parent != NULL &&
        node->parent->kind == AST_FUNC_DEF &&
        node->parent->open_brace_idx == node->open_brace_idx;

    cfmt_ast_t *child = node->first_child;
    size_t i = node->first_tok_idx;

    while (i < node->last_tok_idx) {
        /* If a child starts at this position, descend into it. */
        while (child && child->first_tok_idx < i) child = child->next_sibling;
        if (child && child->first_tok_idx == i) {
            if (emit_node(C, child) != 0) return -1;
            i = child->last_tok_idx;
            child = child->next_sibling;
            continue;
        }

        cfmt_tok_t *t = &C->stream->tokens[i];
        cfmt_action_t *a = &C->result->actions[i];

        if (is_func_body && i == node->open_brace_idx) {
            /* Emit the `{` itself. If this function has lifted literals,
               emit a newline then the declarations. Skip the extra newline
               when there are no declarations — otherwise we'd insert a
               spurious blank line and break idempotence. */
            if (emit_token(C->out, t, a) != 0) return -1;
            cfmt_lit_table_t *tab = &C->result->func_lits[C->func_index];
            if (tab->count > 0) {
                put_cstr(C->out, "\n");
                for (size_t k = 0; k < tab->count; k++) {
                    if (emit_func_scope_decl(C->out, tab->entries[k]) != 0) return -1;
                }
            }
            C->func_index++;
            i++;
            continue;
        }

        if (emit_token(C->out, t, a) != 0) return -1;
        i++;
    }
    return 0;
}

/* --- Public entry -------------------------------------------------------- */

ds_status_t cfmt_emit(cfmt_ast_t        *root,
                      cfmt_tok_stream_t *stream,
                      cfmt_pass_result_t *result,
                      ds_str_t          *out) {
    /* 1. Preamble: file-scope literals. */
    for (size_t i = 0; i < result->file_lits.count; i++) {
        if (emit_file_scope_decl(out, result->file_lits.entries[i]) != 0) {
            return DS_ERR_ALLOC;
        }
    }

    /* 2. Walk the AST emitting all tokens (with actions applied). */
    emit_ctx_t C;
    C.stream = stream;
    C.result = result;
    C.out    = out;
    C.func_index = 0;
    if (emit_node(&C, root) != 0) return DS_ERR_ALLOC;
    return DS_OK;
}

/* ============================================================
 * align.c
 * ============================================================
 */
/*
 * align.c — line aligner.
 *
 * The input is text (the destringer's emit output, or any earlier
 * aligner output if we're checking idempotence). We re-tokenize it with
 * our own lexer so that numbers (including hex floats like 0x1F.8p+2),
 * string literals (including L"..." / u"..." / U"..." / u8"..."), and
 * character literals are all atomic — the aligner never tries to peer
 * inside them.
 *
 * Each significant token then falls into one of two classes:
 *   word:    IDENT / INT_LIT / FLOAT_LIT          (left side)
 *   symbol:  PUNCT / STRING_LIT / CHAR_LIT        (right side)
 *
 * Word atoms get joined with single-space separators. Symbol atoms get
 * concatenated with no separator (whitespace between adjacent punctuators
 * is purely visual; dropping it is valid C). A NEWLINE flushes the current
 * (word, symbol) pair onto one output line, padded to LINE_WIDTH.
 *
 * Preprocessor directives keep their iconic one-line look (with `\`-
 * continuations preserved). We don't try to format individual tokens
 * inside them.
 */



#define LINE_WIDTH 80

static int aln_is_hspace(int c) { return c == ' ' || c == '\t'; }

static int is_word_char(int c) {
    return c == '_'
        || (c >= 'a' && c <= 'z')
        || (c >= 'A' && c <= 'Z')
        || (c >= '0' && c <= '9');
}

static int is_blank(const char *s, size_t n) {
    size_t i;
    for (i = 0; i < n; i++) {
        char c = s[i];
        if (c != ' ' && c != '\t' && c != '\r') return 0;
    }
    return 1;
}

/* Pad word + symbol to LINE_WIDTH columns, with a trailing newline. */
static int emit_pair(const char *wb, size_t wlen,
                     const char *sb, size_t slen,
                     ds_str_t *out) {
    long pad;
    int rc = 0;
    if (wlen + slen == 0) return str_pushc(out, '\n');
    if (wlen > 0) rc |= str_append(out, wb, wlen);
    pad = (long)LINE_WIDTH - (long)wlen - (long)slen;
    if (pad > 0) {
        long k;
        for (k = 0; k < pad; k++) rc |= str_pushc(out, ' ');
    }
    if (slen > 0) rc |= str_append(out, sb, slen);
    rc |= str_pushc(out, '\n');
    return rc;
}

/* Preprocessor line: word prefix (leading `#` glued on) left, the rest of
   the line right-justified. One source line → one output line. Called
   once per `\`-terminated segment of a PP directive's lexeme. */
static int align_pp_line(const char *line, size_t len, ds_str_t *out) {
    size_t start, split, left_end, right_end;
    if (is_blank(line, len)) return str_pushc(out, '\n');

    start = 0;
    while (start < len && aln_is_hspace((unsigned char)line[start])) start++;

    split = start;
    if (split < len && line[split] == '#') split++;
    while (split < len) {
        char c = line[split];
        if (is_word_char((unsigned char)c) || aln_is_hspace((unsigned char)c))
            split++;
        else break;
    }

    /* Function-like macro guard. `#define NAME(args) body` requires NO
       whitespace between NAME and `(`; inserting alignment padding there
       would silently turn the macro into an object-like one. If the next
       character is `(` and it's directly glued to the preceding word
       (no whitespace), consume `(...)` (matching parens) as part of the
       word prefix so padding lands AFTER the closing paren. */
    if (split < len && line[split] == '('
        && split > start
        && !aln_is_hspace((unsigned char)line[split - 1])) {
        int depth = 0;
        while (split < len) {
            char c = line[split];
            if (c == '(') depth++;
            else if (c == ')') depth--;
            split++;
            if (depth == 0) break;
        }
    }

    left_end = split;
    while (left_end > start && aln_is_hspace((unsigned char)line[left_end - 1]))
        left_end--;

    right_end = len;
    while (right_end > split &&
           (aln_is_hspace((unsigned char)line[right_end - 1])
            || line[right_end - 1] == '\r'))
        right_end--;

    return emit_pair(line + start, left_end - start,
                     line + split, right_end - split, out);
}

/* Grow buffer in-place. */
static int reserve(char **buf, size_t *cap, size_t need) {
    char *nb;
    size_t nc;
    if (*cap >= need) return 0;
    nc = *cap ? *cap : 256;
    while (nc < need) nc *= 2;
    nb = (char *)realloc(*buf, nc);
    if (!nb) return -1;
    *buf = nb; *cap = nc;
    return 0;
}

static int append_word(char **buf, size_t *cap, size_t *len,
                       const char *s, size_t n) {
    /* Word atoms get a single-space separator if there's already a word. */
    int rc;
    if (*len > 0) {
        rc = reserve(buf, cap, *len + 1 + n);
        if (rc != 0) return rc;
        (*buf)[(*len)++] = ' ';
    } else {
        rc = reserve(buf, cap, *len + n);
        if (rc != 0) return rc;
    }
    memcpy(*buf + *len, s, n);
    *len += n;
    return 0;
}

static int append_sym(char **buf, size_t *cap, size_t *len,
                      const char *s, size_t n) {
    /* Symbol atoms concatenate directly. */
    int rc = reserve(buf, cap, *len + n);
    if (rc != 0) return rc;
    memcpy(*buf + *len, s, n);
    *len += n;
    return 0;
}

/* Walk a PP_DIRECTIVE token's lexeme, splitting on internal `\n` chars
   (the embedded `\<newline>` continuations) and emitting one aligned line
   per piece. The trailing `\` stays at the end of each continuation line,
   right-justified to col 80, which is the iconic look. */
static int align_pp_token(const cfmt_tok_t *t, ds_str_t *out) {
    const char *lx = t->lexeme;
    size_t      ln = t->lexeme_len;
    size_t      i  = 0;
    while (i < ln) {
        size_t j = i;
        while (j < ln && lx[j] != '\n') j++;
        if (align_pp_line(lx + i, j - i, out) != 0) return -1;
        i = (j < ln) ? j + 1 : j;
    }
    return 0;
}

ds_status_t cfmt_align(const char *in, size_t in_len, ds_str_t *out) {
    ds_context_t      ctx;
    ds_arena_t        arena;
    cfmt_tok_stream_t stream;
    char  *wbuf = NULL, *sbuf = NULL;
    size_t wcap = 0,    scap = 0;
    size_t wlen = 0,    slen = 0;
    ds_status_t st;
    size_t i;
    int rc = 0;

    ds_context_init(&ctx);
    if (ds_arena_create(&arena, 4u * 1024u * 1024u, &ctx) != DS_OK) {
        return DS_ERR_ALLOC;
    }
    ds_context_use_arena(&ctx, &arena);
    memset(&stream, 0, sizeof(stream));

    st = cfmt_lex(in, in_len, &ctx, &arena, &stream);
    if (st != DS_OK) {
        if (stream.tokens) free(stream.tokens);
        ds_arena_destroy(&arena, &ctx);
        return st;
    }

    /* `pp_pending_nl` is set right after a PP_DIRECTIVE was emitted (which
       already wrote a trailing '\n'); the lexer's NEWLINE for that same
       source line then gets consumed silently to avoid a doubled newline. */
    int pp_pending_nl = 0;

    for (i = 0; i < stream.count && rc == 0; i++) {
        const cfmt_tok_t *t = &stream.tokens[i];
        switch (t->kind) {
            case TOK_NEWLINE:
                if (pp_pending_nl) {
                    pp_pending_nl = 0;
                } else {
                    rc = emit_pair(wbuf, wlen, sbuf, slen, out);
                    wlen = slen = 0;
                }
                break;

            case TOK_PP_DIRECTIVE:
                if (wlen > 0 || slen > 0) {
                    rc = emit_pair(wbuf, wlen, sbuf, slen, out);
                    wlen = slen = 0;
                }
                if (rc == 0) rc = align_pp_token(t, out);
                pp_pending_nl = 1;
                break;

            case TOK_WHITESPACE:
            case TOK_COMMENT_LINE:
            case TOK_COMMENT_BLOCK:
                /* Stripped — comments are gone by design; whitespace is
                   re-synthesized as padding. */
                break;

            case TOK_IDENT:
            case TOK_INT_LIT:
            case TOK_FLOAT_LIT:
                /* A new word arriving after we've already collected a
                   symbol means the previous (word, symbol) pair is done. */
                if (slen > 0) {
                    rc = emit_pair(wbuf, wlen, sbuf, slen, out);
                    wlen = slen = 0;
                }
                if (rc == 0)
                    rc = append_word(&wbuf, &wcap, &wlen,
                                     t->lexeme, t->lexeme_len);
                break;

            case TOK_PUNCT:
            case TOK_STRING_LIT:
            case TOK_CHAR_LIT:
                /* Atomic on the symbol side. String/char literal lexemes
                   already include any L/u/U/u8 prefix and surrounding
                   quotes, so they survive the right-justify intact. */
                rc = append_sym(&sbuf, &scap, &slen,
                                t->lexeme, t->lexeme_len);
                break;

            case TOK_EOF:
                /* Trailing pair, if any. */
                if (wlen > 0 || slen > 0) {
                    rc = emit_pair(wbuf, wlen, sbuf, slen, out);
                    wlen = slen = 0;
                }
                break;

            default:
                break;
        }
    }

    free(wbuf);
    free(sbuf);
    if (stream.tokens) free(stream.tokens);
    ds_arena_destroy(&arena, &ctx);
    return (rc == 0) ? DS_OK : DS_ERR_ALLOC;
}

/* ============================================================
 * main.c
 * ============================================================
 */
/*
 * main.c — aligner CLI.
 *
 * Stage 1: just expose the lexer for testing.
 *
 *   aligner --lex FILE    print each token (kind, line:col, lexeme)
 *   aligner FILE          [stage 5+] full pipeline (not yet implemented)
 */



static int read_file(const char *path, char **out_buf, size_t *out_len) {
    FILE *f = fopen(path, "rb");
    if (!f) return -1;
    if (fseek(f, 0, SEEK_END) != 0) { fclose(f); return -1; }
    long n = ftell(f);
    if (n < 0) { fclose(f); return -1; }
    if (fseek(f, 0, SEEK_SET) != 0) { fclose(f); return -1; }
    char *buf = (char *)malloc((size_t)n + 1);
    if (!buf) { fclose(f); return -1; }
    size_t got = fread(buf, 1, (size_t)n, f);
    fclose(f);
    buf[got] = '\0';
    *out_buf = buf;
    *out_len = got;
    return 0;
}

/* Print a token in a parseable form. Escapes lexeme for display. */
static void print_tok(const cfmt_tok_t *t, FILE *out) {
    fprintf(out, "%-13s %u:%-3u len=%-3zu",
            cfmt_tok_kind_name(t->kind),
            t->line, t->col, t->lexeme_len);

    if (t->kind == TOK_STRING_LIT) {
        fprintf(out, " enc=%d bytes=%zu", (int)t->u.str.enc, t->u.str.byte_count);
    } else if (t->kind == TOK_CHAR_LIT) {
        fprintf(out, " enc=%d value=%lu", (int)t->u.chr.enc, t->u.chr.value);
    }

    fputs(" |", out);
    for (size_t i = 0; i < t->lexeme_len; i++) {
        unsigned char c = (unsigned char)t->lexeme[i];
        if (c == '\n')      fputs("\\n",  out);
        else if (c == '\t') fputs("\\t",  out);
        else if (c == '\r') fputs("\\r",  out);
        else if (c < 32)    fprintf(out, "\\x%02x", c);
        else                fputc((int)c, out);
    }
    fputs("|\n", out);
}

static int cmd_lex(const char *path) {
    char *src = NULL;
    size_t len = 0;
    if (read_file(path, &src, &len) != 0) {
        fprintf(stderr, "aligner: cannot read %s\n", path);
        return 1;
    }

    ds_context_t ctx;
    ds_arena_t   arena;
    ds_context_init(&ctx);
    /* 4 MiB arena: enough for typical input + decoded literals. */
    if (ds_arena_create(&arena, 4u * 1024u * 1024u, &ctx) != DS_OK) {
        fprintf(stderr, "aligner: arena alloc failed\n");
        free(src);
        return 1;
    }
    ds_context_use_arena(&ctx, &arena);

    cfmt_tok_stream_t stream;
    memset(&stream, 0, sizeof(stream));

    ds_status_t st = cfmt_lex(src, len, &ctx, &arena, &stream);
    if (st != DS_OK) {
        fprintf(stderr, "aligner: lex failed (%s)\n", ds_status_name(st));
        free(stream.tokens);
        ds_arena_destroy(&arena, &ctx);
        free(src);
        return 1;
    }

    for (size_t i = 0; i < stream.count; i++) {
        print_tok(&stream.tokens[i], stdout);
    }

    free(stream.tokens);
    ds_arena_destroy(&arena, &ctx);
    free(src);
    return 0;
}

static int cmd_ast(const char *path) {
    char *src = NULL;
    size_t len = 0;
    if (read_file(path, &src, &len) != 0) {
        fprintf(stderr, "aligner: cannot read %s\n", path);
        return 1;
    }

    ds_context_t ctx;
    ds_arena_t   arena;
    ds_context_init(&ctx);
    if (ds_arena_create(&arena, 16u * 1024u * 1024u, &ctx) != DS_OK) {
        fprintf(stderr, "aligner: arena alloc failed\n");
        free(src);
        return 1;
    }
    ds_context_use_arena(&ctx, &arena);

    cfmt_tok_stream_t stream;
    memset(&stream, 0, sizeof(stream));
    if (cfmt_lex(src, len, &ctx, &arena, &stream) != DS_OK) {
        fprintf(stderr, "aligner: lex failed\n");
        free(stream.tokens); ds_arena_destroy(&arena, &ctx); free(src);
        return 1;
    }

    cfmt_ast_t *root = cfmt_parse(&stream, &ctx);
    if (!root) {
        fprintf(stderr, "aligner: parse failed\n");
        free(stream.tokens); ds_arena_destroy(&arena, &ctx); free(src);
        return 1;
    }
    cfmt_ast_dump(root, &stream, stdout);

    free(stream.tokens);
    ds_arena_destroy(&arena, &ctx);
    free(src);
    return 0;
}

static int cmd_destring(const char *path) {
    char *src = NULL;
    size_t len = 0;
    if (read_file(path, &src, &len) != 0) {
        fprintf(stderr, "aligner: cannot read %s\n", path);
        return 1;
    }
    ds_context_t ctx; ds_arena_t arena;
    ds_context_init(&ctx);
    if (ds_arena_create(&arena, 16u * 1024u * 1024u, &ctx) != DS_OK) {
        fprintf(stderr, "aligner: arena alloc failed\n");
        free(src); return 1;
    }
    ds_context_use_arena(&ctx, &arena);

    cfmt_tok_stream_t stream; memset(&stream, 0, sizeof(stream));
    if (cfmt_lex(src, len, &ctx, &arena, &stream) != DS_OK) {
        fprintf(stderr, "aligner: lex failed\n");
        free(stream.tokens); ds_arena_destroy(&arena, &ctx); free(src);
        return 1;
    }
    cfmt_ast_t *root = cfmt_parse(&stream, &ctx);
    if (!root) {
        fprintf(stderr, "aligner: parse failed\n");
        free(stream.tokens); ds_arena_destroy(&arena, &ctx); free(src);
        return 1;
    }

    cfmt_pass_result_t result;
    if (cfmt_pass_result_init(&result, &stream, &ctx) != DS_OK) {
        fprintf(stderr, "aligner: pass init failed\n");
        free(stream.tokens); ds_arena_destroy(&arena, &ctx); free(src);
        return 1;
    }
    if (cfmt_pass_destring(root, &stream, &result) != DS_OK) {
        fprintf(stderr, "aligner: destring pass failed\n");
        free(stream.tokens); ds_arena_destroy(&arena, &ctx); free(src);
        return 1;
    }

    /* Summary. */
    printf("File-scope literals: %zu unique\n", result.file_lits.count);
    for (size_t i = 0; i < result.file_lits.count; i++) {
        const cfmt_lit_entry_t *e = result.file_lits.entries[i];
        printf("  s%08x  %zu bytes: \"", e->hash, e->byte_count);
        for (size_t j = 0; j < e->byte_count && j < 40; j++) {
            unsigned char c = e->bytes[j];
            if (c == '\n') fputs("\\n", stdout);
            else if (c < 32 || c >= 127) printf("\\x%02x", c);
            else putchar((int)c);
        }
        if (e->byte_count > 40) fputs("...", stdout);
        printf("\"\n");
    }
    printf("\nFunctions: %zu\n", result.func_lits_count);
    for (size_t i = 0; i < result.func_lits_count; i++) {
        const cfmt_lit_table_t *t = &result.func_lits[i];
        if (t->count == 0) continue;
        printf("  func[%zu]: %zu unique literals\n", i, t->count);
        for (size_t j = 0; j < t->count; j++) {
            const cfmt_lit_entry_t *e = t->entries[j];
            printf("    s%08x  %zu bytes: \"", e->hash, e->byte_count);
            for (size_t k = 0; k < e->byte_count && k < 32; k++) {
                unsigned char c = e->bytes[k];
                if (c == '\n') fputs("\\n", stdout);
                else if (c < 32 || c >= 127) printf("\\x%02x", c);
                else putchar((int)c);
            }
            if (e->byte_count > 32) fputs("...", stdout);
            printf("\"\n");
        }
    }

    /* Actions. */
    size_t n_var = 0, n_brace = 0, n_omit = 0, n_char = 0;
    for (size_t i = 0; i < result.actions_count; i++) {
        switch (result.actions[i].kind) {
            case CFMT_ACT_VAR_REF:    n_var++; break;
            case CFMT_ACT_BRACE_INIT: n_brace++; break;
            case CFMT_ACT_OMIT:       n_omit++; break;
            case CFMT_ACT_CHAR_NUM:   n_char++; break;
            default: break;
        }
    }
    printf("\nActions: VAR_REF=%zu BRACE_INIT=%zu OMIT=%zu CHAR_NUM=%zu\n",
           n_var, n_brace, n_omit, n_char);

    free(stream.tokens);
    free(result.actions);
    /* result.file_lits.entries and func_lits arrays were realloc'd, free them */
    free(result.file_lits.entries);
    for (size_t i = 0; i < result.func_lits_count; i++) {
        free(result.func_lits[i].entries);
    }
    free(result.func_lits);
    ds_arena_destroy(&arena, &ctx);
    free(src);
    return 0;
}

/* Full pipeline: lex → parse → destring → emit → align → stdout. */
static int cmd_format(const char *path) {
    char *src = NULL;
    size_t len = 0;
    if (read_file(path, &src, &len) != 0) {
        fprintf(stderr, "aligner: cannot read %s\n", path);
        return 1;
    }
    ds_context_t ctx; ds_arena_t arena;
    ds_context_init(&ctx);
    if (ds_arena_create(&arena, 64u * 1024u * 1024u, &ctx) != DS_OK) {
        fprintf(stderr, "aligner: arena alloc failed\n");
        free(src); return 1;
    }
    ds_context_use_arena(&ctx, &arena);

    cfmt_tok_stream_t stream; memset(&stream, 0, sizeof(stream));
    if (cfmt_lex(src, len, &ctx, &arena, &stream) != DS_OK) {
        fprintf(stderr, "aligner: lex failed\n"); return 1;
    }
    cfmt_ast_t *root = cfmt_parse(&stream, &ctx);
    if (!root) { fprintf(stderr, "aligner: parse failed\n"); return 1; }

    cfmt_pass_result_t result;
    if (cfmt_pass_result_init(&result, &stream, &ctx) != DS_OK ||
        cfmt_pass_destring(root, &stream, &result) != DS_OK) {
        fprintf(stderr, "aligner: destring failed\n"); return 1;
    }

    ds_str_t *emitted = str_create();
    if (!emitted) { fprintf(stderr, "aligner: emit-buffer alloc failed\n"); return 1; }
    if (cfmt_emit(root, &stream, &result, emitted) != DS_OK) {
        fprintf(stderr, "aligner: emit failed\n"); return 1;
    }

    ds_str_t *aligned = str_create();
    if (!aligned) { fprintf(stderr, "aligner: align-buffer alloc failed\n"); return 1; }
    if (cfmt_align(FUNC_str_data(emitted), FUNC_str_len(emitted), aligned) != DS_OK) {
        fprintf(stderr, "aligner: align failed\n"); return 1;
    }

    fwrite(FUNC_str_data(aligned), 1, FUNC_str_len(aligned), stdout);

    str_destroy(emitted);
    str_destroy(aligned);
    free(stream.tokens);
    free(result.actions);
    free(result.file_lits.entries);
    for (size_t i = 0; i < result.func_lits_count; i++) {
        free(result.func_lits[i].entries);
    }
    free(result.func_lits);
    ds_arena_destroy(&arena, &ctx);
    free(src);
    return 0;
}

static void usage(FILE *out) {
    fputs(
        "usage: aligner [--lex|--ast|--destring|--emit] FILE\n"
        "  --lex        dump the token stream and exit\n"
        "  --ast        dump the AST and exit\n"
        "  --destring   show what the destringer pass plans to do\n"
        "  --emit       emit unaligned post-destring text (no alignment)\n"
        "  (without flags, run the full pipeline)\n",
        out);
}

/* Like --format but stops after emit (unaligned). */
static int cmd_emit_only(const char *path) {
    char *src = NULL; size_t len = 0;
    if (read_file(path, &src, &len) != 0) return 1;
    ds_context_t ctx; ds_arena_t arena;
    ds_context_init(&ctx);
    ds_arena_create(&arena, 64u * 1024u * 1024u, &ctx);
    ds_context_use_arena(&ctx, &arena);
    cfmt_tok_stream_t stream; memset(&stream, 0, sizeof(stream));
    cfmt_lex(src, len, &ctx, &arena, &stream);
    cfmt_ast_t *root = cfmt_parse(&stream, &ctx);
    cfmt_pass_result_t result;
    cfmt_pass_result_init(&result, &stream, &ctx);
    cfmt_pass_destring(root, &stream, &result);
    ds_str_t *out = str_create();
    cfmt_emit(root, &stream, &result, out);
    fwrite(FUNC_str_data(out), 1, FUNC_str_len(out), stdout);
    str_destroy(out);
    free(stream.tokens);
    free(result.actions);
    free(result.file_lits.entries);
    for (size_t i = 0; i < result.func_lits_count; i++) free(result.func_lits[i].entries);
    free(result.func_lits);
    ds_arena_destroy(&arena, &ctx);
    free(src);
    return 0;
}

int main(int argc, char **argv) {
    if (argc < 2) { usage(stderr); return 2; }
    if (strcmp(argv[1], "--help") == 0 || strcmp(argv[1], "-h") == 0) {
        usage(stdout);
        return 0;
    }
    if (strcmp(argv[1], "--lex") == 0) {
        if (argc < 3) { usage(stderr); return 2; }
        return cmd_lex(argv[2]);
    }
    if (strcmp(argv[1], "--ast") == 0) {
        if (argc < 3) { usage(stderr); return 2; }
        return cmd_ast(argv[2]);
    }
    if (strcmp(argv[1], "--destring") == 0) {
        if (argc < 3) { usage(stderr); return 2; }
        return cmd_destring(argv[2]);
    }
    if (strcmp(argv[1], "--emit") == 0) {
        if (argc < 3) { usage(stderr); return 2; }
        return cmd_emit_only(argv[2]);
    }
    /* Default: full pipeline. */
    return cmd_format(argv[1]);
}
